class ContributionTracker:
    """Track per-user contributions to detect and limit abuse."""

    def __init__(self):
        self.contributions = {}  # user_id -> list of contribution metadata
        self.flagged_users = set()
        self.contribution_hashes = set()  # detect duplicate submissions

    def record_contribution(self, user_id: str, data_hash: str, label: int, num_samples: int):
        if user_id not in self.contributions:
            self.contributions[user_id] = []
        self.contributions[user_id].append({
            'timestamp': datetime.utcnow().isoformat(),
            'data_hash': data_hash,
            'label': label,
            'num_samples': num_samples,
        })

    def get_user_contribution_count(self, user_id: str) -> int:
        return sum(c['num_samples'] for c in self.contributions.get(user_id, []))

    def is_duplicate(self, data_hash: str) -> bool:
        return data_hash in self.contribution_hashes

    def add_hash(self, data_hash: str):
        self.contribution_hashes.add(data_hash)

    def get_label_distribution(self, user_id: str) -> dict:
        """Check if a user is submitting heavily skewed labels."""
        dist = {}
        for c in self.contributions.get(user_id, []):
            label = c['label']
            dist[label] = dist.get(label, 0) + c['num_samples']
        return dist

    def is_label_distribution_suspicious(self, user_id: str) -> bool:
        """Flag users whose label distribution is heavily skewed."""
        dist = self.get_label_distribution(user_id)
        if not dist:
            return False
        total = sum(dist.values())
        if total < 10:
            return False
        max_ratio = max(dist.values()) / total
        # If more than 90% of contributions are a single label, suspicious
        return max_ratio > 0.9

    def flag_user(self, user_id: str):
        self.flagged_users.add(user_id)
        logger.warning(f"User {user_id} has been flagged for suspicious activity")

    def is_flagged(self, user_id: str) -> bool:
        return user_id in self.flagged_users


class DataValidator:
    """Validate incoming training data for integrity and safety."""

    @staticmethod
    def validate_image(image_bytes: bytes) -> Optional[np.ndarray]:
        """Validate and sanitize an uploaded image."""
        try:
            img = Image.open(io.BytesIO(image_bytes))

            # Re-encode to strip any embedded payloads or metadata
            # This prevents steganographic attacks and malicious metadata
            clean_buffer = io.BytesIO()
            img_rgb = img.convert('RGB')
            img_rgb.save(clean_buffer, format='PNG')
            clean_buffer.seek(0)
            img_clean = Image.open(clean_buffer)

            img_resized = img_clean.resize(IMAGE_SIZE)
            arr = np.array(img_resized, dtype=np.float32)

            # Validate pixel value range
            if arr.min() < 0 or arr.max() > 255:
                logger.warning("Image has out-of-range pixel values")
                return None

            # Normalize
            arr = arr / 255.0

            # Check for degenerate images (all same color, noise-only, etc.)
            if arr.std() < 0.01:
                logger.warning("Image appears to be degenerate (near-constant)")
                return None

            return arr

        except Exception as e:
            logger.error(f"Image validation failed: {e}")
            return None

    @staticmethod
    def validate_label(label, num_classes: int) -> Optional[int]:
        """Validate a label value."""
        try:
            label_int = int(label)
            if 0 <= label_int < num_classes:
                return label_int
            logger.warning(f"Label {label_int} out of range [0, {num_classes})")
            return None
        except (ValueError, TypeError):
            logger.warning(f"Invalid label value: {label}")
            return None

    @staticmethod
    def validate_csv(csv_bytes: bytes, max_rows: int = 1000) -> Optional[pd.DataFrame]:
        """Validate CSV structure and content."""
        try:
            df = pd.read_csv(io.BytesIO(csv_bytes), nrows=max_rows)

            if len(df) == 0:
                logger.warning("Empty CSV file")
                return None

            if len(df) > max_rows:
                logger.warning(f"CSV exceeds max rows ({max_rows})")
                return None

            # Check for required columns
            required_cols = {'image_path', 'label'}
            if not required_cols.issubset(set(df.columns)):
                # Alternative: pixel data format
                if 'label' not in df.columns:
                    logger.warning("CSV missing 'label' column")
                    return None

            # Validate no code injection in string fields
            for col in df.select_dtypes(include=['object']).columns:
                # Check for suspicious patterns
                suspicious_patterns = ['__import__', 'eval(', 'exec(', 'os.', 'subprocess',
                                       '<script', 'javascript:', '${', '`']
                for pattern in suspicious_patterns:
                    mask = df[col].astype(str).str.contains(pattern, case=False, na=False)
                    if mask.any():
                        logger.warning(f"Suspicious content detected in column '{col}'")
                        return None

            return df

        except Exception as e:
            logger.error(f"CSV validation failed: {e}")
            return None

    @staticmethod
    def compute_data_hash(data: bytes) -> str:
        """Compute SHA-256 hash of data for deduplication and integrity."""
        return hashlib.sha256(data).hexdigest()


class StatisticalOutlierDetector:
    """Detect statistical outliers in training data contributions."""

    def __init__(self):
        self.feature_stats = {}  # label -> {'mean': array, 'std': array, 'count': int}

    def update_stats(self, features: np.ndarray, label: int):
        """Update running statistics for a label class."""
        flat = features.flatten()
        if label not in self.feature_stats:
            self.feature_stats[label] = {
                'mean': flat.copy(),
                'M2': np.zeros_like(flat),
                'count': 1
            }
        else:
            stats = self.feature_stats[label]
            stats['count'] += 1
            delta = flat - stats['mean']
            stats['mean'] += delta / stats['count']
            delta2 = flat - stats['mean']
            stats['M2'] += delta * delta2

    def is_outlier(self, features: np.ndarray, label: int, threshold: float = 4.0) -> bool:
        """Check if a sample is a statistical outlier for its claimed label."""
        if label not in self.feature_stats:
            return False  # Can't determine outlier status without history

        stats = self.feature_stats[label]
        if stats['count'] < 30:
            return False  # Not enough data to determine outliers

        flat = features.flatten()
        variance = stats['M2'] / (stats['count'] - 1)
        std = np.sqrt(np.maximum(variance, 1e-10))
        z_scores = np.abs((flat - stats['mean']) / std)
        mean_z = np.mean(z_scores)

        return mean_z > threshold


class QuarantineManager:
    """Manage quarantined data pending review/validation."""

    def __init__(self, quarantine_dir: str, approved_dir: str):
        self.quarantine_dir = quarantine_dir
        self.approved_dir = approved_dir
        self.quarantine_log = []

    def quarantine(self, data: np.ndarray, label: int, user_id: str,
                   reason: str, data_hash: str) -> str:
        """Place data in quarantine with metadata."""
        entry_id = str(uuid.uuid4())
        entry = {
            'id': entry_id,
            'user_id': user_id,
            'label': label,
            'reason': reason,
            'data_hash': data_hash,
            'timestamp': datetime.utcnow().isoformat(),
            'status': 'quarantined'
        }

        # Save data
        np.save(os.path.join(self.quarantine_dir, f"{entry_id}.npy"), data)
        self.quarantine_log.append(entry)

        logger.info(f"Data quarantined: {entry_id}, reason: {reason}")
        return entry_id

    def approve(self, entry_id: str) -> bool:
        """Move data from quarantine to approved."""
        for entry in self.quarantine_log:
            if entry['id'] == entry_id and entry['status'] == 'quarantined':
                src = os.path.join(self.quarantine_dir, f"{entry_id}.npy")
                dst = os.path.join(self.approved_dir, f"{entry_id}.npy")
                if os.path.exists(src):
                    os.rename(src, dst)
                    entry['status'] = 'approved'
                    logger.info(f"Data approved: {entry_id}")
                    return True
        return False

    def reject(self, entry_id: str) -> bool:
        """Reject and delete quarantined data."""
        for entry in self.quarantine_log:
            if entry['id'] == entry_id and entry['status'] == 'quarantined':
                path = os.path.join(self.quarantine_dir, f"{entry_id}.npy")
                if os.path.exists(path):
                    os.remove(path)
                entry['status'] = 'rejected'
                logger.info(f"Data rejected: {entry_id}")
                return True
        return False

    def get_quarantined_items(self):
        return [e for e in self.quarantine_log if e['status'] == 'quarantined']


# --- Model Building ---

def build_model(num_classes: int = NUM_CLASSES) -> tf.keras.Model:
    """Build a simple image classification model."""
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(*IMAGE_SIZE, 3)),
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    return model


# --- Training Pipeline with Robust Aggregation ---

class SecureTrainingPipeline:
    """Training pipeline with anti-poisoning measures."""

    def __init__(self):
        self.model = build_model()
        self.tracker = ContributionTracker()
        self.validator = DataValidator()
        self.outlier_detector = StatisticalOutlierDetector()
        self.quarantine_mgr = QuarantineManager(QUARANTINE_FOLDER, APPROVED_FOLDER)
        self.training_data = []  # List of (features, label, user_id, weight)
        self.validation_set = None
        self._initialize_validation_set()

    def _initialize_validation_set(self):
        """Create a small trusted validation set for monitoring model quality."""
        # In production, this would be a curated, trusted dataset
        # Using synthetic data as placeholder
        np.random.seed(42)
        num_val = 100
        val_images = np.random.rand(num_val, *IMAGE_SIZE, 3).astype(np.float32)
        val_labels = np.random.randint(0, NUM_CLASSES, num_val)
        self.validation_set = (val_images, val_labels)
        logger.info("Initialized trusted validation set")

    def _compute_contribution_weight(self, user_id: str) -> float:
        """Compute trust weight for a user's contribution."""
        if self.tracker.is_flagged(user_id):
            return 0.0

        # New users get lower weight, established contributors get higher
        count = self.tracker.get_user_contribution_count(user_id)
        if count < 5:
            return 0.5
        elif count < 50:
            return 0.8
        else:
            return 1.0

    def add_training_sample(self, image_data: np.ndarray, label: int,
                            user_id: str, data_hash: str) -> dict:
        """Add a validated training sample with anti-poisoning checks."""

        # Check if user is flagged
        if self.tracker.is_flagged(user_id):
            return {'status': 'rejected', 'reason': 'User account is flagged'}

        # Check per-user contribution limits
        if self.tracker.get_user_contribution_count(user_id) >= MAX_SAMPLES_PER_USER:
            return {'status': 'rejected', 'reason': 'Contribution limit reached'}

        # Check for duplicate submissions
        if self.tracker.is_duplicate(data_hash):
            return {'status': 'rejected', 'reason': 'Duplicate submission detected'}

        # Statistical outlier detection
        is_outlier = self.outlier_detector.is_outlier(image_data, label)

        if is_outlier:
            # Quarantine suspicious data
            entry_id = self.quarantine_mgr.quarantine(
                image_data, label, user_id,
                reason='Statistical outlier detected',
                data_hash=data_hash
            )
            self.tracker.record_contribution(user_id, data_hash, label, 1)
            self.tracker.add_hash(data_hash)

            # Check if user's label distribution is suspicious
            if self.tracker.is_label_distribution_suspicious(user_id):
                self.tracker.flag_user(user_id)

            return {
                'status': 'quarantined',
                'reason': 'Data flagged for review',
                'entry_id': entry_id
            }

        # Compute trust weight
        weight = self._compute_contribution_weight(user_id)

        # Update statistics
        self.outlier_detector.update_stats(image_data, label)

        # Add to training data
        self.training_data.append((image_data, label, user_id, weight))
        self.tracker.record_contribution(user_id, data_hash, label, 1)
        self.tracker.add_hash(data_hash)

        return {'status': 'accepted', 'weight': weight}

    def train(self, epochs: int = 5, batch_size: int = 32) -> dict:
        """Train the model with weighted samples and validation monitoring."""
        if len(self.training_data) < 10:
            return {'status': 'error', 'message': 'Insufficient training data (minimum 10 samples)'}

        # Prepare training data with weights
        images = np.array([d[0] for d in self.training_data])
        labels = np.array([d[1] for d in self.training_data])
        weights = np.array([d[3] for d in self.training_data])

        # Get baseline validation performance
        val_images, val_labels = self.validation_set
        baseline_loss, baseline_acc = self.model.evaluate(val_images, val_labels, verbose=0)

        # Save model weights before training (for rollback)
        pre_train_weights = self.model.get_weights()

        # Train with sample weights
        history = self.model.fit(
            images, labels,
            sample_weight=weights,
            epochs=epochs,
            batch_size=batch_size,
            validation_data=self.validation_set,
            verbose=1
        )

        # Post-training validation check
        post_loss, post_acc = self.model.evaluate(val_images, val_labels, verbose=0)

        # Rollback if validation performance degrades significantly
        # This prevents successful poisoning attacks from persisting
        if post_acc < baseline_acc - 0.1:  # More than 10% accuracy drop
            logger.warning(
                f"Validation accuracy dropped from {baseline_acc:.4f} to {post_acc:.4f}. "
                f"Rolling back model weights."
            )
            self.model.set_weights(pre_train_weights)
            return {
                'status': 'rolled_back',
                'message': 'Training caused validation degradation, model rolled back',
                'baseline_accuracy': float(baseline_acc),
                'post_train_accuracy': float(post_acc)
            }

        # Save model
        self.model.save(MODEL_PATH)

        return {
            'status': 'success',
            'epochs': epochs,
            'training_samples': len(self.training_data),
            'baseline_accuracy': float(baseline_acc),
            'final_accuracy': float(post_acc),
            'final_loss': float(post_loss),
            'history': {
                'loss': [float(v) for v in history.history['loss']],
                'accuracy': [float(v) for v in history.history.get('accuracy', [])],
            }
        }


# Initialize pipeline
pipeline = SecureTrainingPipeline()


# --- Authentication Middleware ---

def get_user_id():
    """Extract user ID from request. In production, use proper auth (JWT, OAuth, etc.)."""
    user_id = request.headers.get('X-User-ID')
    if not user_id:
        return None
    # Sanitize user ID
    user_id = secure_filename(user_id)
    if not user_id or len(user_id) > 128:
        return None
    return user_id


def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = get_user_id()
        if not user_id:
            return jsonify({'error': 'Authentication required. Provide X-User-ID header.'}), 401
        return f(user_id=user_id, *args, **kwargs)
    return decorated


def require_admin(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        admin_key = request.headers.get('X-Admin-Key')
        if admin_key != os.environ.get('ADMIN_KEY', 'change-me-in-production'):
            return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated


