@app.route('/api/upload/image', methods=['POST'])
@require_auth
def upload_image(user_id):
    """Upload a single image with label for training."""
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    label_str = request.form.get('label')
    if label_str is None:
        return jsonify({'error': 'No label provided'}), 400

    # Validate label
    label = pipeline.validator.validate_label(label_str, NUM_CLASSES)
    if label is None:
        return jsonify({'error': f'Invalid label. Must be integer in [0, {NUM_CLASSES})'}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    # Read and validate image
    image_bytes = file.read()
    data_hash = pipeline.validator.compute_data_hash(image_bytes)

    image_array = pipeline.validator.validate_image(image_bytes)
    if image_array is None:
        return jsonify({'error': 'Invalid or corrupted image'}), 400

    # Add to training pipeline with anti-poisoning checks
    result = pipeline.add_training_sample(image_array, label, user_id, data_hash)

    status_code = 200 if result['status'] == 'accepted' else 202 if result['status'] == 'quarantined' else 400
    return jsonify(result), status_code


@app.route('/api/upload/csv', methods=['POST'])
@require_auth
def upload_csv(user_id):
    """Upload a CSV file containing training data (pixel values + labels)."""
    if 'csv' not in request.files:
        return jsonify({'error': 'No CSV file provided'}), 400

    file = request.files['csv']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    filename = secure_filename(file.filename)
    if not filename.endswith('.csv'):
        return jsonify({'error': 'File must be a CSV'}), 400

    csv_bytes = file.read()
    df = pipeline.validator.validate_csv(csv_bytes)
    if df is None:
        return jsonify({'error': 'Invalid CSV file'}), 400

    results = {'accepted': 0, 'quarantined': 0, 'rejected': 0, 'errors': []}

    # Process CSV rows - expecting pixel data format
    # Columns: label, pixel_0, pixel_1, ..., pixel_N
    if 'image_path' not in df.columns:
        # Pixel data format
        label_col = df['label']
        pixel_cols = [c for c in df.columns if c != 'label']

        if len(pixel_cols) == 0:
            return jsonify({'error': 'No pixel data columns found'}), 400

        expected_pixels = IMAGE_SIZE[0] * IMAGE_SIZE[1] * 3

        for idx, row in df.iterrows():
            label = pipeline.validator.validate_label(row['label'], NUM_CLASSES)
            if label is None:
                results['errors'].append(f"Row {idx}: invalid label")
                results['rejected'] += 1
                continue

            try:
                pixels = row[pixel_cols].values.astype(np.float32)

                if len(pixels) != expected_pixels:
                    # Try to reshape what we have
                    results['errors'].append(
                        f"Row {idx}: expected {expected_pixels} pixels, got {len(pixels)}")
                    results['rejected'] += 1
                    continue

                image_array = pixels.reshape((*IMAGE_SIZE, 3))

                # Validate range
                if image_array.max() > 1.0:
                    image_array = image_array / 255.0

                if image_array.min() < 0 or image_array.max() > 1.0:
                    results['errors'].append(f"Row {idx}: pixel values out of range")
                    results['rejected'] += 1
                    continue

                # Check for degenerate data
                if image_array.std() < 0.01:
                    results['errors'].append(f"Row {idx}: degenerate image data")
                    results['rejected'] += 1
                    continue

                data_hash = hashlib.sha256(pixels.tobytes()).hexdigest()
                result = pipeline.add_training_sample(image_array, label, user_id, data_hash)
                results[result['status']] = results.get(result['status'], 0) + 1

            except Exception as e:
                results['errors'].append(f"Row {idx}: {str(e)}")
                results['rejected'] += 1

    else:
        return jsonify({
            'error': 'Image path references in CSV are not supported for security reasons. '
                     'Please use pixel data format or upload images individually.'
        }), 400

    return jsonify({
        'status': 'processed',
        'summary': {
            'accepted': results['accepted'],
            'quarantined': results['quarantined'],
            'rejected': results['rejected'],
            'errors': results['errors'][:10]  # Limit error messages
        }
    }), 200


