@app.route('/api/predict', methods=['POST'])
def predict():
    """Make a prediction on an uploaded image."""
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    file = request.files['image']
    image_bytes = file.read()
    image_array = pipeline.validator.validate_image(image_bytes)

    if image_array is None:
        return jsonify({'error': 'Invalid image'}), 400

    # Make prediction
    input_array = np.expand_dims(image_array, axis=0)
    predictions = pipeline.model.predict(input_array, verbose=0)
    predicted_class = int(np.argmax(predictions[0]))
    confidence = float(predictions[0][predicted_class])

    return jsonify({
        'predicted_class': predicted_class,
        'confidence': confidence,
        'all_probabilities': {str(i): float(p) for i, p in enumerate(predictions[0])}
    }), 200


